import{c as e,a7 as r,y as n,B as p}from"./chunks/framework.3cjvm90C.js";const b=JSON.parse('{"title":"OpenDILab 决策智能平台","description":"介绍 OpenDILab 决策智能开源平台的工具与课程资源","frontmatter":{"title":"OpenDILab 决策智能平台","description":"介绍 OpenDILab 决策智能开源平台的工具与课程资源"},"headers":[],"relativePath":"rlwiki/papers/opendilab.md","filePath":"rlwiki/papers/opendilab.md","lastUpdated":1782448598000}'),t={name:"rlwiki/papers/opendilab.md"};function h(l,a,o,i,f,s){return r(),n("div",null,[...a[0]||(a[0]=[p('<h3 id="opendilab" tabindex="-1">OpenDILab <a class="header-anchor" href="#opendilab" aria-label="Permalink to “OpenDILab”">​</a></h3><h4 id="ppofamaily-决策智能公开课" tabindex="-1">PPOFamaily 决策智能公开课 <a class="header-anchor" href="#ppofamaily-决策智能公开课" aria-label="Permalink to “PPOFamaily  决策智能公开课”">​</a></h4><p><strong>PPO × Family Vol.1</strong> 系统性地讲解了决策智能的核心算法技术——<strong>深度强化学习</strong>，并深入浅出地介绍了最强大通用的算法 PPO。</p><p><a href="https://zhuanlan.zhihu.com/p/604897017" target="_blank" rel="noreferrer">OpenDILab 浦策：课程实录｜ PPO × Family 第一课：开启决策 AI 探索之旅 （上）</a></p><p><a href="https://zhuanlan.zhihu.com/p/606954674" target="_blank" rel="noreferrer">OpenDILab 浦策：课程实录｜ PPO × Family 第一课：开启决策 AI 探索之旅 （下）</a></p><p><strong>PPO × Family Vol.2 ——解构复杂动作空间</strong>从决策输出设计的角度展开，介绍了 PPO 算法在四种动作空间上的各类技巧。</p><p><a href="https://zhuanlan.zhihu.com/p/612669849" target="_blank" rel="noreferrer">OpenDILab 浦策：课程实录｜ PPO × Family 第二课：解构复杂动作空间（上）</a></p><p><a href="https://zhuanlan.zhihu.com/p/622866136" target="_blank" rel="noreferrer">OpenDILab 浦策：课程实录｜ PPO × Family 第二课：解构复杂动作空间（下）</a></p><p><strong>PPO × Family Vol.3 ——表征多模态观察空间</strong>，则将会从表征建模，从深度学习的角度进行展开，介绍观察空间的三部曲及衍生的“算法-代码-实践”知识。</p><p><a href="https://zhuanlan.zhihu.com/p/635313705" target="_blank" rel="noreferrer">OpenDILab 浦策：课程实录｜ PPO × Family 第三课：表征多模态观察空间（上）</a></p><p><a href="https://zhuanlan.zhihu.com/p/636696175" target="_blank" rel="noreferrer">OpenDILab 浦策：课程实录｜ PPO × Family 第三课：表征多模态观察空间（下）</a></p><p>而<strong>PPO × Family Vol.4 ——解密稀疏奖励空间，将会进入到 MDP 的第三大核心元素——奖励函数，从指导智能体探索和利用的角度，介绍奖励空间上的“两朵乌云”及衍生的“算法-代码-实践”知识。</strong></p><p><a href="https://zhuanlan.zhihu.com/p/642656409" target="_blank" rel="noreferrer">OpenDILab 浦策：课程实录｜ PPO × Family 第四课：解密稀疏奖励空间（上）</a></p><p><a href="https://zhuanlan.zhihu.com/p/642812757" target="_blank" rel="noreferrer">OpenDILab 浦策：课程实录｜ PPO × Family 第四课：解密稀疏奖励空间（中）</a></p><p><a href="https://zhuanlan.zhihu.com/p/643047368" target="_blank" rel="noreferrer">OpenDILab 浦策：课程实录｜ PPO × Family 第四课：解密稀疏奖励空间（下）</a></p><h4 id="opendilab-实践指南" tabindex="-1">OpenDILab 实践指南 <a class="header-anchor" href="#opendilab-实践指南" aria-label="Permalink to “OpenDILab 实践指南”">​</a></h4><p><a href="https://zhuanlan.zhihu.com/p/654237727" target="_blank" rel="noreferrer">OpenDILab 实践指南（ 1）： RL 算法/环境速查表（ cheatsheet）</a></p><p><a href="https://zhuanlan.zhihu.com/p/656886757" target="_blank" rel="noreferrer">OpenDILab 实践指南（ 3）：深入浅出配置文件系统</a></p><p><a href="https://zhuanlan.zhihu.com/p/658146912" target="_blank" rel="noreferrer">OpenDILab 实践指南（ 4）：算法-代码对应解读文档</a></p><p><a href="https://zhuanlan.zhihu.com/p/660266568" target="_blank" rel="noreferrer">OpenDILab 实践指南（ 5）：高效构建决策环境</a></p><h4 id="mcts-的前沿动态" tabindex="-1">MCTS 的前沿动态 <a class="header-anchor" href="#mcts-的前沿动态" aria-label="Permalink to “MCTS 的前沿动态”">​</a></h4><p><a href="https://zhuanlan.zhihu.com/p/650009275" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 1）： AlphaZero</a></p><p><a href="https://zhuanlan.zhihu.com/p/654059774" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 2）： MuZero</a></p><p><a href="https://zhuanlan.zhihu.com/p/657484426" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 3）： Sampled MuZero</a></p><p><a href="https://zhuanlan.zhihu.com/p/662943334" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 4）： EfficientZero</a></p><p><a href="https://zhuanlan.zhihu.com/p/664542805" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 5）： Stochastic MuZero</a></p><p><a href="https://zhuanlan.zhihu.com/p/670885213" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 6）：浅析 MCTS 算法原理演进史</a></p><p><a href="https://zhuanlan.zhihu.com/p/675867274" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 7）： Gumbel MuZero</a></p><p><a href="https://zhuanlan.zhihu.com/p/678489535" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 8）： MuZero Unplugged</a></p><p><a href="https://zhuanlan.zhihu.com/p/681839624" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 9）：可视化分析 AlphaZero/MuZero 中的表征、策略和知识</a></p><p><a href="https://zhuanlan.zhihu.com/p/684528177" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 10）：使用多方面的先验知识强化 MCTS Agent</a></p><p><a href="https://zhuanlan.zhihu.com/p/688093451" target="_blank" rel="noreferrer">MCTS + RL 系列技术博客（ 11）： MCTS 效率优化前沿进展</a></p><p><a href="https://zhuanlan.zhihu.com/p/633462726" target="_blank" rel="noreferrer">如何追踪 MCTS 的前沿动态？（ 1）</a></p><p><a href="https://zhuanlan.zhihu.com/p/635570518" target="_blank" rel="noreferrer">如何追踪 MCTS 的前沿动态？（ 2）</a></p><p><a href="https://zhuanlan.zhihu.com/p/641713866" target="_blank" rel="noreferrer">如何追踪 MCTS 的前沿动态？（ 3）</a></p><p><a href="https://zhuanlan.zhihu.com/p/643382412" target="_blank" rel="noreferrer">如何追踪 MCTS 的前沿动态？（ 4）</a></p>',36)])])}const m=e(t,[["render",h]]);export{b as __pageData,m as default};
